    this.geometry.dispose();
    this.material.dispose();
  }

  private writeBuffers(): void {
    const accent = new Color(this.currentSystem.accent);
    const secondary = new Color(this.currentSystem.secondary);
    const rose = new Color(0xf5a3b7);

